+
+const MARKDOWN_STYLE_MARKERS = {
+  bold: { open: "**", close: "**" },
+  italic: { open: "_", close: "_" },
+  strikethrough: { open: "~~", close: "~~" },
+  code: { open: "`", close: "`" },
+  code_block: { open: "```\n", close: "```" },
